INSERT INTO public.tools (id, slug, name, website_url, logo_url, short_description, long_description, category, subcategories, capabilities, best_for, not_recommended_for, pricing_type, free_plan_available, free_trial_available, starting_monthly_price, pricing_currency, pricing_notes, api_available, webhooks_available, direct_integrations, import_formats, export_formats, supported_platforms, technical_difficulty, no_code_friendly, open_source, self_hostable, privacy_level, data_retention_notes, supports_india, reliability_score, editorial_quality_score, verification_status, last_verified_at, is_active)
VALUES
('tool-google-search', 'google-search', 'Google Search API', 'https://developers.google.com/custom-search', '🔍', 'Programmatic web search and query indexing.', 'Google Custom Search JSON API allows web developers to retrieve and display search results from Google Search programmatically.', 'research', ARRAY['Search Engine', 'Web Scraper'], ARRAY['web_search', 'news_fetching', 'link_scraping'], 'Fetching real-time accurate information from the web to ground LLM outputs.', 'Deep database queries or batch scanning of specific enterprise records.', 'freemium', TRUE, TRUE, 5, 'USD', 'First 100 queries per day are free. Thereafter, $5 per 1,000 queries.', TRUE, FALSE, ARRAY['make', 'zapier', 'n8n', 'pipedream'], ARRAY['JSON'], ARRAY['JSON'], ARRAY['Web', 'Cloud'], 'intermediate', FALSE, FALSE, FALSE, 'medium', 'Queries may be logged by Google in accordance with API terms of service.', TRUE, 10.0, 9.0, 'verified', '2026-06-01', TRUE),
('tool-feedly', 'feedly', 'Feedly', 'https://feedly.com', '🟢', 'News aggregator and RSS content curation platform.', 'Feedly is an AI-powered market intelligence and feed aggregation platform.', 'research', ARRAY['Content Curation', 'RSS'], ARRAY['rss_feed', 'article_monitoring', 'newsletter_tracking'], 'Monitoring industry blogs, newsletters, and news sources systematically.', 'Natural language conversations or text generation.', 'freemium', TRUE, TRUE, 6, 'USD', 'Free for up to 100 feeds. Paid plans unlock AI Feedly Leo filters starting at $6/month.', TRUE, TRUE, ARRAY['slack', 'make', 'zapier', 'n8n', 'google-sheets'], ARRAY['OPML', 'XML'], ARRAY['OPML', 'JSON'], ARRAY['Web', 'iOS', 'Android'], 'beginner', TRUE, FALSE, FALSE, 'medium', 'User feeds and boards are retained on Feedly secure cloud.', TRUE, 9.0, 8.0, 'verified', '2026-05-15', TRUE),
('tool-perplexity', 'perplexity', 'Perplexity AI', 'https://perplexity.ai', '🌀', 'Conversational answer engine with real-time web search.', 'Perplexity AI is an AI-powered search engine that answers natural language queries using citations.', 'research', ARRAY['AI Search', 'Information Retrieval'], ARRAY['web_search', 'text_synthesis', 'citation_generation'], 'Synthesising vast search queries with real-time citations and sources.', 'Structured database transactions or high-throughput batch task pipelines.', 'freemium', TRUE, FALSE, 20, 'USD', 'Free basic search. Pro plan ($20/mo) unlocks advanced models and files upload.', TRUE, FALSE, ARRAY['make', 'zapier'], ARRAY['TXT', 'PDF'], ARRAY['TXT', 'PDF'], ARRAY['Web', 'iOS', 'Android'], 'non_technical', TRUE, FALSE, FALSE, 'medium', 'Search history is saved in account unless turned off in settings.', TRUE, 9.0, 9.0, 'verified', '2026-06-10', TRUE),
('tool-gemini', 'gemini', 'Google Gemini', 'https://ai.google.dev', '✦', 'Google''s powerful, multimodal AI model series with large context window.', 'Google Gemini is a highly capable family of models featuring advanced multimodal reasoning, text generation, and a ground-breaking context window of up to 2 million tokens.', 'research', ARRAY['LLM', 'Generative AI'], ARRAY['text_generation', 'image_understanding', 'structured_json_output', 'long_context'], 'Analysing large PDFs, complex multi-step reasoning, and generating high-quality structured content.', 'Direct desktop application automation without a middleware API.', 'usage_based', TRUE, FALSE, 0, 'INR', 'Generous free tier on AI Studio. Pay-as-you-go pricing based on input/output tokens.', TRUE, FALSE, ARRAY['make', 'zapier', 'n8n', 'pipedream', 'github', 'vercel'], ARRAY['TXT', 'PDF', 'Images', 'Audio', 'Video'], ARRAY['JSON', 'TXT'], ARRAY['Web', 'API'], 'intermediate', TRUE, FALSE, FALSE, 'high', 'API data is not used for model training if using paid/enterprise tiers.', TRUE, 9.5, 9.0, 'verified', '2026-07-01', TRUE),
('tool-claude', 'claude', 'Anthropic Claude', 'https://anthropic.com/claude', '✉️', 'Claude is a state-of-the-art conversational LLM focused on safety and nuance.', 'Anthropic Claude (e.g. Claude 3.5 Sonnet) is an industry-leading model family praised for advanced coding, nuanced creative writing, high-accuracy comprehension, and friendly, natural dialogue.', 'research', ARRAY['LLM', 'Generative AI'], ARRAY['text_generation', 'coding', 'reasoning', 'document_analysis'], 'Nuanced writing, complex software development, precise text summaries, and critical thinking.', 'Real-time web browsing without search grounding tools.', 'usage_based', TRUE, FALSE, 20, 'USD', 'Free tier on web interface. API is charged per million tokens.', TRUE, FALSE, ARRAY['make', 'zapier', 'n8n', 'pipedream', 'github'], ARRAY['TXT', 'PDF', 'JSON', 'Images'], ARRAY['TXT', 'JSON'], ARRAY['Web', 'API'], 'intermediate', TRUE, FALSE, FALSE, 'high', 'Anthropic does not train models on API data. Data is deleted after 30 days unless required for compliance.', TRUE, 9.5, 9.5, 'verified', '2026-07-02', TRUE),
('tool-chatgpt', 'chatgpt', 'OpenAI ChatGPT', 'https://openai.com', '🤖', 'OpenAI''s benchmark generative AI conversational model.', 'ChatGPT (GPT-4o) is OpenAI''s flagship conversational and multimodal model.', 'research', ARRAY['LLM', 'Generative AI'], ARRAY['text_generation', 'web_browsing', 'data_analysis', 'image_generation'], 'General purpose AI assistance, complex automation, and structured calculations.', 'Locally hosted offline workflows without internet access.', 'freemium', TRUE, FALSE, 20, 'USD', 'Free basic access. Plus is $20/mo. API is priced per-token.', TRUE, FALSE, ARRAY['make', 'zapier', 'n8n', 'pipedream', 'google-sheets', 'notion'], ARRAY['CSV', 'TXT', 'PDF', 'Images'], ARRAY['TXT', 'JSON', 'PNG'], ARRAY['Web', 'iOS', 'Android', 'API'], 'beginner', TRUE, FALSE, FALSE, 'medium', 'API data is not trained on. Web app data is trained on unless opted out.', TRUE, 9.8, 9.0, 'verified', '2026-07-05', TRUE),
('tool-openrouter', 'openrouter', 'OpenRouter AI', 'https://openrouter.ai', '🔌', 'Unified router and API gateway for dozens of open and closed LLMs.', 'OpenRouter provides a standardized API endpoint to access Claude, GPT-4, LLaMA, Gemini, and dozens of other open-source models with competitive, real-time pricing.', 'development', ARRAY['AI Infrastructure', 'API Aggregator'], ARRAY['text_generation', 'model_routing', 'unified_billing'], 'Deploying applications that require switching models instantly without updating code.', 'Purely client-side applications without an intermediate server.', 'usage_based', TRUE, FALSE, 0, 'USD', 'Charges strictly by token usage based on the underlying model.', TRUE, FALSE, ARRAY['make', 'n8n', 'pipedream', 'github'], ARRAY['JSON'], ARRAY['JSON'], ARRAY['Web', 'API'], 'developer', FALSE, TRUE, FALSE, 'medium', 'Routes payloads securely. Data retention subject to underlying model providers selected.', TRUE, 9.3, 9.0, 'verified', '2026-06-25', TRUE),
('tool-canva', 'canva', 'Canva Pro', 'https://canva.com', '🎨', 'Visual design platform with extensive templates and AI tools.', 'Canva is a highly visual, drag-and-drop design platform that simplifies content creation, social media posts, presentation decks, and visual graphics.', 'content_creation', ARRAY['Graphic Design', 'Social Assets'], ARRAY['image_editing', 'presentation_creation', 'video_layout', 'ai_image_magic'], 'Creating beautiful, branded social media posts, headers, and slides quickly.', 'High-level professional UI vector drawing or database warehousing.', 'freemium', TRUE, TRUE, 13, 'USD', 'Free basic templates. Pro plan ($13/month) unlocks advanced AI and branding kits.', TRUE, FALSE, ARRAY['slack', 'make', 'zapier', 'buffer'], ARRAY['PNG', 'JPG', 'PDF', 'SVG'], ARRAY['PNG', 'JPG', 'PDF', 'SVG', 'MP4'], ARRAY['Web', 'iOS', 'Android'], 'non_technical', TRUE, FALSE, FALSE, 'medium', 'All user assets are held securely on Canva cloud servers.', TRUE, 9.7, 9.2, 'verified', '2026-05-20', TRUE),
('tool-recraft', 'recraft', 'Recraft AI', 'https://recraft.ai', '📐', 'Generative AI art board for designers specializing in vector art.', 'Recraft AI is an infinite art board designed for visual professionals. It generates beautiful, brand-aligned vectors, icons, and illustrations.', 'content_creation', ARRAY['AI Graphic Design', 'Vector Generator'], ARRAY['vector_generation', 'style_control', 'icon_design', 'palette_matching'], 'Generating high-quality, scalable SVG graphics and matching visual icons.', 'Bulk text processing, analytical reporting, or raw photograph edits.', 'freemium', TRUE, FALSE, 20, 'USD', 'Free tier generates public images. Paid tier ($20/mo) makes creations private.', TRUE, FALSE, ARRAY['make'], ARRAY['PNG', 'JPG'], ARRAY['SVG', 'PNG', 'Lottie'], ARRAY['Web', 'API'], 'beginner', TRUE, FALSE, FALSE, 'medium', 'Free tier images are publicly viewable on community feeds.', TRUE, 9.2, 9.5, 'verified', '2026-06-15', TRUE),
('tool-buffer', 'buffer', 'Buffer', 'https://buffer.com', '📊', 'Social media scheduling, publishing, and analytical toolkit.', 'Buffer is an easy-to-use publishing platform that schedules posts, manages channels, and tracks analytics.', 'marketing', ARRAY['Social Scheduler', 'Analytics'], ARRAY['post_scheduling', 'social_publishing', 'performance_analytics'], 'Planning and scheduling social media posts in batches safely.', 'Drafting the copy or generating content directly.', 'freemium', TRUE, TRUE, 6, 'USD', 'Free for up to 3 social channels and 10 scheduled posts.', TRUE, TRUE, ARRAY['canva', 'make', 'zapier', 'n8n'], ARRAY['CSV', 'TXT'], ARRAY['CSV', 'PDF'], ARRAY['Web', 'iOS', 'Android'], 'beginner', TRUE, FALSE, FALSE, 'high', 'Maintains standard social authorization tokens and post histories.', TRUE, 9.6, 9.0, 'verified', '2026-07-03', TRUE),
('tool-make', 'make', 'Make.com', 'https://make.com', '🟣', 'Visual automation and integration platform to connect apps.', 'Make.com is a visual integration platform that allows users to connect APIs, automate workflows, and design complex pipelines.', 'productivity', ARRAY['Integration Platform', 'Workflow Automation'], ARRAY['webhook_handling', 'api_integration', 'conditional_routing', 'data_mapping'], 'No-code and low-code integrations with visual drag-and-drop workflows.', 'Ultra high-speed local script execution or local hardware control.', 'freemium', TRUE, TRUE, 9, 'USD', 'Free plan includes 1,000 operations per month. Core plan starts at $9/month.', TRUE, TRUE, ARRAY['google-sheets', 'slack', 'notion', 'gmail', 'zapier', 'hubspot', 'stripe'], ARRAY['JSON'], ARRAY['JSON'], ARRAY['Web', 'Cloud'], 'intermediate', TRUE, FALSE, FALSE, 'high', 'SOC2 compliant. Execution logs are stored securely.', TRUE, 9.8, 9.5, 'verified', '2026-07-10', TRUE),
('tool-zapier', 'zapier', 'Zapier', 'https://zapier.com', '🟠', 'The gold standard of simple, pre-built web app automations.', 'Zapier connects over 6,000 apps with simple ''if-this-then-that'' formulas.', 'productivity', ARRAY['Integration Platform', 'Workflow Automation'], ARRAY['webhook_handling', 'api_integration', 'conditional_logic'], 'Quickly connecting standard web apps without writing any code.', 'Complex looping or highly cost-sensitive high-volume tasks.', 'freemium', TRUE, TRUE, 20, 'USD', 'Free plan limited to single-step Zaps. Multi-step require Starter ($20/mo).', TRUE, TRUE, ARRAY['google-sheets', 'slack', 'notion', 'gmail', 'hubspot', 'stripe'], ARRAY['JSON'], ARRAY['JSON'], ARRAY['Web', 'Cloud'], 'beginner', TRUE, FALSE, FALSE, 'high', 'Highly secure enterprise privacy. Data logged for task histories.', TRUE, 9.9, 9.6, 'verified', '2026-07-09', TRUE),
('tool-n8n', 'n8n', 'n8n.io', 'https://n8n.io', '🔴', 'Fair-code node-based workflow automation, highly self-hostable.', 'n8n is an extendable workflow automation tool that lets you host on your own server or in the cloud.', 'productivity', ARRAY['Integration Platform', 'Workflow Automation'], ARRAY['webhook_handling', 'api_integration', 'code_execution', 'self_hosting'], 'High-volume automations, complex logic requiring code, and self-hosting privacy.', 'Absolute beginners who do not understand JSON formats.', 'freemium', TRUE, TRUE, 20, 'USD', 'Free forever if self-hosted. Cloud pricing starts at $20/month.', TRUE, TRUE, ARRAY['google-sheets', 'slack', 'notion', 'gmail', 'hubspot', 'stripe', 'supabase'], ARRAY['JSON'], ARRAY['JSON'], ARRAY['Docker', 'Web', 'Cloud', 'Self-hosted'], 'intermediate', TRUE, TRUE, TRUE, 'high', 'Self-hosting ensures 100% data ownership.', TRUE, 9.5, 9.3, 'verified', '2026-07-08', TRUE),
('tool-google-sheets', 'google-sheets', 'Google Sheets', 'https://google.com/sheets', '📗', 'Web-based collaborative spreadsheet editor.', 'Google Sheets is a cloud-based spreadsheet program. Highly flexible and collaborative.', 'productivity', ARRAY['Spreadsheet', 'Database'], ARRAY['data_storage', 'csv_export', 'real_time_collaboration'], 'Storing raw text, managing queues, manual logging, and basic data reports.', 'High-performance relational transactions or very large datasets.', 'free', TRUE, FALSE, 0, 'INR', 'Free for individual accounts. Part of Google Workspace for businesses.', TRUE, TRUE, ARRAY['gmail', 'make', 'zapier', 'n8n', 'pipedream', 'slack'], ARRAY['CSV', 'XLSX', 'TSV'], ARRAY['CSV', 'XLSX', 'PDF'], ARRAY['Web', 'iOS', 'Android'], 'non_technical', TRUE, FALSE, FALSE, 'medium', 'Secured under standard Google Cloud infrastructure.', TRUE, 10.0, 9.5, 'verified', '2026-07-01', TRUE),
('tool-airtable', 'airtable', 'Airtable', 'https://airtable.com', '🗂️', 'Low-code visual relational database and collaboration platform.', 'Airtable blends the ease of a spreadsheet with the power of a relational database.', 'productivity', ARRAY['No-code Database', 'Workspace Management'], ARRAY['relational_data', 'view_filtering', 'form_input', 'automation_triggers'], 'Managing visual content calendars, structured project logs, and inventory pipelines.', 'High-throughput database reads/writes of millions of records.', 'freemium', TRUE, TRUE, 20, 'USD', 'Free basic plan. Paid plan is $20/month per user.', TRUE, TRUE, ARRAY['slack', 'make', 'zapier', 'n8n', 'notion'], ARRAY['CSV', 'XLSX'], ARRAY['CSV', 'JSON'], ARRAY['Web', 'iOS', 'Android'], 'beginner', TRUE, FALSE, FALSE, 'high', 'Highly secure cloud database with SOC 2 compliance.', TRUE, 9.8, 9.6, 'verified', '2026-07-11', TRUE),
('tool-notion', 'notion', 'Notion', 'https://notion.so', '📓', 'Connected workspace for notes, wiki, docs, and databases.', 'Notion is an all-in-one workspace featuring customizable wikis, rich text notes, project boards, and inline relational databases.', 'productivity', ARRAY['Knowledge Base', 'Notes', 'Database'], ARRAY['document_collaboration', 'rich_text', 'visual_databases'], 'Compiling meeting notes, structured user wikis, and visual boards.', 'Serving as a fast, low-latency relational database for dynamic web applications.', 'freemium', TRUE, FALSE, 8, 'USD', 'Free for individual usage. Plus starts at $8/month per user.', TRUE, TRUE, ARRAY['slack', 'make', 'zapier', 'n8n', 'github', 'google-sheets'], ARRAY['Markdown', 'CSV', 'HTML', 'DOCX'], ARRAY['Markdown', 'PDF', 'HTML', 'CSV'], ARRAY['Web', 'Mac', 'Windows', 'iOS', 'Android'], 'beginner', TRUE, FALSE, FALSE, 'medium', 'Workspace data is held securely on Notion''s servers.', TRUE, 9.7, 9.7, 'verified', '2026-07-12', TRUE),
('tool-supabase', 'supabase', 'Supabase', 'https://supabase.com', '⚡', 'Open source Firebase alternative providing PostgreSQL database and Auth.', 'Supabase is a developer-centric open-source platform that instantly provisions a real PostgreSQL database with full row-level security.', 'development', ARRAY['Database', 'Backend as a Service'], ARRAY['sql_relational_data', 'user_auth', 'real_time_events', 'file_storage'], 'Production web applications needing a secure, scale-to-zero relational SQL database with authentication.', 'Non-technical users who do not understand schemas, SQL, or web API mechanics.', 'freemium', TRUE, FALSE, 25, 'USD', 'Free tier offers 2 active projects. Pro tier starts at $25/month.', TRUE, TRUE, ARRAY['github', 'vercel', 'n8n'], ARRAY['SQL', 'CSV', 'JSON'], ARRAY['SQL', 'CSV', 'JSON'], ARRAY['Cloud', 'Self-hosted'], 'developer', FALSE, TRUE, TRUE, 'high', 'Full Row-Level Security. Data managed on AWS instances.', TRUE, 9.8, 9.5, 'verified', '2026-07-06', TRUE),
('tool-github', 'github', 'GitHub', 'https://github.com', '🐙', 'Git repository hosting and developer collaboration hub.', 'GitHub hosts Git source code repositories and facilitates software versioning, issue tracking, and automated deployment.', 'development', ARRAY['Version Control', 'DevOps'], ARRAY['code_repository', 'ci_cd_pipelines', 'issue_tracking'], 'Managing source code, trigger builds, and coordinating engineering task streams.', 'General purpose notes archiving.', 'freemium', TRUE, FALSE, 4, 'USD', 'Free for unlimited repositories. Copilot and Team are paid.', TRUE, TRUE, ARRAY['vercel', 'slack', 'make', 'zapier', 'n8n', 'pipedream', 'supabase'], ARRAY['Git'], ARRAY['Git', 'ZIP'], ARRAY['Web', 'Mac', 'Windows', 'Linux'], 'developer', FALSE, FALSE, TRUE, 'high', 'Highly compliant SOC 2. Repository privacy options available.', TRUE, 9.9, 9.8, 'verified', '2026-07-04', TRUE),
