('tool-slack', 'slack', 'Slack', 'https://slack.com', '💬', 'Real-time communication and channel hub for modern workspaces.', 'Slack is a messaging application that organizes communication into channels.', 'productivity', ARRAY['Team Chat', 'Alerts'], ARRAY['channel_alerts', 'team_messaging', 'slash_commands', 'interactive_buttons'], 'Sending daily workflow reports, server status alerts, and centralizing team conversations.', 'Serving as a primary client-facing CRM database or document store.', 'freemium', TRUE, TRUE, 7, 'USD', 'Free with 90-day history limit. Pro tier starts at $7.25/month.', TRUE, TRUE, ARRAY['make', 'zapier', 'n8n', 'pipedream', 'github', 'google-sheets', 'notion'], ARRAY['JSON'], ARRAY['JSON', 'HTML'], ARRAY['Web', 'Mac', 'Windows', 'Linux', 'iOS', 'Android'], 'non_technical', TRUE, FALSE, FALSE, 'high', 'Encrypted in transit and rest. Compliant with HIPAA, SOC2.', TRUE, 9.9, 9.6, 'verified', '2026-07-02', TRUE),
